import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import { useLocation } from "@reach/router";
import BinanceClone from "@screens/binance-clone-script";
import Layout_v2 from "@components/layout_v2";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const BinanceCloneScript = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Binance Clone Script", link: null },
  ];
  const { data } = props;
  const location = useLocation();
  const fileUrl =
    data?.binanceCloneScriptImg?.childImageSharp?.gatsbyImageData?.images
      ?.fallback?.src;
  const validData = data?.allMetaJson?.nodes[0];
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Product",
        name: "Binance Clone Script | Binance Clone App Development",
        description:
          "Launch your own crypto exchange instantly with Justtry Technologies’ Binance Clone Script, which enables businesses to customize and launch a crypto exchange with the enterprise-grade features Binance Clone App.",
        url: "https://justtrytech.com/binance-clone-script/",
        brand: {
          "@type": "Brand",
          name: "Justtry Technologies",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: 4.9,
          reviewCount: 578,
        },
      },

      {
        "@type": "Organization",
        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "Binance clone script by Justtry Technologies is a ready-made crypto exchange solution with advanced features, customization, and revenue tools for entrepreneurs.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce)",
          addressLocality: "Madurai",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
          addressCountry: "IN",
        },
      },

      {
        "@type": "FAQPage",
        mainEntity: [
          {
            "@type": "Question",
            name: "How to launch a cryptocurrency exchange platform?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Launch a cryptocurrency exchange by using Justtry Technologies’ Binance clone script, a ready-made centralized exchange solution with core features, customization, wallet setup, and liquidity integration.",
            },
          },
          {
            "@type": "Question",
            name: "What are the top platforms offering Binance clone scripts?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Justtry Technologies offers an advanced Binance clone script featuring market and margin trading, multi-coin support, staking, referral tools, and real-time charts for building a trading environment.",
            },
          },
          {
            "@type": "Question",
            name: "Which companies provide ready-made Binance clone scripts for cryptocurrency exchanges?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Justtry Technologies provides a ready-made Binance clone script designed to help entrepreneurs quickly create a high-performance crypto exchange with customizable features and built-in functionality.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        image={fileUrl}
        description={validData?.description}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <BinanceClone db={db} />
    </Layout_v2>
  );
};

export default BinanceCloneScript;

export const queryData = graphql`
  query MyQuery {
    binanceCloneScriptImg: file(
      relativePath: { eq: "binance-clone-script.png" }
    ) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "binance-clone-script" } }) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
